"use client";

import type { SVGProps } from "react";

import styles from "./magic-wand-motion.module.css";

export interface MagicWandMotionProps extends Omit<SVGProps<SVGSVGElement>, "title"> {
  isAnimated?: boolean;
  size?: number;
  title?: string | null;
}

export function MagicWandMotion({
  className,
  isAnimated = false,
  size = 32,
  title = "Magic wand",
  ...props
}: MagicWandMotionProps) {
  const hasAccessibleName = Boolean(title || props["aria-label"] || props["aria-labelledby"]);

  return (
    <svg
      fill="currentColor"
      {...props}
      aria-hidden={hasAccessibleName ? props["aria-hidden"] : true}
      className={[isAnimated ? styles.isAnimating : "", className].filter(Boolean).join(" ")}
      height={size}
      role={props.role ?? (hasAccessibleName ? "img" : undefined)}
      viewBox="0 0 32 32"
      width={size}
    >
      {title ? <title>{title}</title> : null}
      <path
        className={styles.Wand}
        d="M29.4141,24,12,6.5859a2.0476,2.0476,0,0,0-2.8281,0l-2.586,2.586a2.0021,2.0021,0,0,0,0,2.8281L23.999,29.4141a2.0024,2.0024,0,0,0,2.8281,0l2.587-2.5865a1.9993,1.9993,0,0,0,0-2.8281ZM8,10.5859,10.5859,8l5,5-2.5866,2.5869-5-5ZM25.4131,28l-11-10.999L17,14.4141l11,11Z"
      />
      <g className={styles.SparkleLeftContainer}>
        <path className={styles.SparkleLeft} d="M2.586 14.586H5.414V17.414H2.586z" />
      </g>
      <path className={styles.SparkleCenter} d="M2.586 2.586H5.414V5.414H2.586z" />
      <g className={styles.SparkleRightContainer}>
        <path className={styles.SparkleRight} d="M14.586 2.586H17.414V5.414H14.586z" />
      </g>
    </svg>
  );
}

.Wand {
  transform-origin: 90% 90%;
  will-change: transform;
}

.SparkleLeft,
.SparkleCenter,
.SparkleRight {
  transform: rotate(45deg);
  will-change: transform;
}

.SparkleLeft,
.SparkleLeftContainer {
  transform-origin: 12.5% 50%;
}

.SparkleCenter {
  transform-origin: 12.5% 12.5%;
}

.SparkleRight,
.SparkleRightContainer {
  transform-origin: 50% 12.5%;
}

.SparkleLeftContainer,
.SparkleRightContainer {
  will-change: transform;
}

.isAnimating .Wand { animation: wand 280ms; }
.isAnimating .SparkleLeft { animation: sparkle-left-translate 280ms; }
.isAnimating .SparkleLeftContainer { animation: sparkle-left-scale 280ms; }
.isAnimating .SparkleCenter { animation: sparkle-center-scale 280ms; }
.isAnimating .SparkleRight { animation: sparkle-right-translate 280ms; }
.isAnimating .SparkleRightContainer { animation: sparkle-right-scale 280ms; }

@keyframes wand {
  0% { transform: rotate(0); animation-timing-function: cubic-bezier(0, 0, 0.83, 1); }
  38.3% { transform: rotate(4deg); animation-timing-function: cubic-bezier(0.66, 0, 0.34, 1); }
  56.6% { transform: rotate(-4deg); animation-timing-function: cubic-bezier(0.34, 0, 0.34, 1); }
  100% { transform: rotate(0); }
}

@keyframes sparkle-left-translate {
  0% { transform: translateY(0) rotate(45deg); animation-timing-function: cubic-bezier(0.34, 0, 0.34, 1); }
  38.3% { transform: translateY(2px) rotate(45deg); animation-timing-function: cubic-bezier(0.34, 0, 0.34, 1); }
  100% { transform: translateY(0) rotate(45deg); }
}

@keyframes sparkle-left-scale {
  0% { transform: scale(1); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  16.6% { transform: scale(1.5); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  43.3% { transform: scale(1); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  60% { transform: scale(1.5); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  100% { transform: scale(1); }
}

@keyframes sparkle-center-scale {
  0% { transform: scale(1) rotate(45deg); }
  23.3% { transform: scale(1) rotate(45deg); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  50% { transform: scale(1.5) rotate(45deg); animation-timing-function: cubic-bezier(0, 0, 0.83, 1); }
  66.6% { transform: scale(1) rotate(45deg); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  83.3% { transform: scale(1.5) rotate(45deg); animation-timing-function: cubic-bezier(0, 0, 0.83, 1); }
  100% { transform: scale(1) rotate(45deg); }
}

@keyframes sparkle-right-translate {
  0% { transform: translateX(0) rotate(45deg); animation-timing-function: cubic-bezier(0.34, 0, 0.34, 1); }
  38.3% { transform: translateX(2px) rotate(45deg); animation-timing-function: cubic-bezier(0.34, 0, 0.34, 1); }
  100% { transform: translateX(0) rotate(45deg); }
}

@keyframes sparkle-right-scale {
  0% { transform: scale(1); }
  13.3% { transform: scale(1); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  30% { transform: scale(1.5); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  56.6% { transform: scale(1); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  73.3% { transform: scale(1.5); animation-timing-function: cubic-bezier(0, 0, 0.3, 1); }
  100% { transform: scale(1); }
}

@media (prefers-reduced-motion: reduce) {
  .isAnimating .Wand,
  .isAnimating .SparkleLeft,
  .isAnimating .SparkleLeftContainer,
  .isAnimating .SparkleCenter,
  .isAnimating .SparkleRight,
  .isAnimating .SparkleRightContainer {
    animation: none;
  }
}
